export function fromWsdbSyncBlock(o: WsdbSyncBlock): MsgpackWsdbSyncBlock {
  if (o.blocknumber === undefined) { throw new Error("Expected blocknumber in WsdbSyncBlock serialization"); }
  if (o.blockstateref === undefined) { throw new Error("Expected blockstateref in WsdbSyncBlock serialization"); }
  if (o.blockheaderhash === undefined) { throw new Error("Expected blockheaderhash in WsdbSyncBlock serialization"); }
  if (o.paddednotehashes === undefined) { throw new Error("Expected paddednotehashes in WsdbSyncBlock serialization"); }
  if (o.paddedl1tol2messages === undefined) { throw new Error("Expected paddedl1tol2messages in WsdbSyncBlock serialization"); }
  if (o.paddednullifiers === undefined) { throw new Error("Expected paddednullifiers in WsdbSyncBlock serialization"); }
  if (o.publicdatawrites === undefined) { throw new Error("Expected publicdatawrites in WsdbSyncBlock serialization"); };
  return {
  blockNumber: o.blocknumber,
  blockStateRef: o.blockstateref,
  blockHeaderHash: o.blockheaderhash,
  paddedNoteHashes: o.paddednotehashes,
  paddedL1ToL2Messages: o.paddedl1tol2messages,
  paddedNullifiers: o.paddednullifiers.map((v: any) => fromNullifierLeafValue(v)),
  publicDataWrites: o.publicdatawrites.map((v: any) => fromPublicDataLeafValue(v)),
  };
}

